  config: { name: "Make Batch Control", position: [2384, 336], parameters: {"jsCode": "const g = $('Loop Over Groups').first().json;\nconst N = g.expectedSegments || 0;\nconst G = g.expectedGroups || 1;\nconst gi = g.groupIndex || 0;\nlet cum = 0;\nfor (let k = 0; k <= gi; k++) cum += Math.floor(N / G) + (k < N % G ? 1 : 0);\nconst groupSize = Math.floor(N / G) + (gi < N % G ? 1 : 0);\nconst perSegmentMs = 240000;\nconst batchMaxWaitMs = Math.min(groupSize * perSegmentMs, 5400000);\nconsole.log('[Batch] group ' + gi + '/' + (G - 1) + ' (' + groupSize + ' segments) -> target ' + cum + '/' + N + ' rows, budget ' + Math.round(batchMaxWaitMs / 60000) + 'min');\nreturn [{ json: { runId: g.runId, groupIndex: gi, expectedGroups: G, expectedSegments: N, cumTarget: cum, pollStartMs: Date.now(), batchMaxWaitMs: batchMaxWaitMs } }];"} },
