const build_Prospect_Payload = node({
  type: "n8n-nodes-base.code",
  version: 2,
  config: { name: "Build Prospect Payload", position: [4720, 96], parameters: {"jsCode": "const rows = $('Decode Protected Emails').all().map(r => r.json);\nconst meta = (($('Build Search Query').first() || {}).json) || {};\nconst decideMeta = (($('Decide: Should Hunt?').first() || {}).json) || {};\nconst campaignId = (decideMeta.campaignId || meta.campaignId || '').toString();\nconst isBad = (e) => { const s = String(e == null ? '' : e).trim().toLowerCase(); if (!s) return true; if (s.indexOf('@') < 0) return true; if (s.indexOf('protected') >= 0) return true; if (s.indexOf('[email') >= 0) return true; if (s.indexOf('cloudflare') >= 0) return true; if (s.indexOf('example.') >= 0) return true; return false; };\nconst prospects = [];\nfor (const r of rows) {\n  const email = (r.Email || '').toString().trim();\n  const companyName = (r['Company Name'] || '').toString().trim();\n  if (!companyName) continue;\n  const status = (r.Status || '').toString().trim();\n  const emailVerified = !!(email && !isBad(email) && status === '');\n  prospects.push({\n    email: emailVerified ? email : '',\n    companyName: companyName,\n    website: (r.Website || '').toString().trim(),\n    city: (r.City || '').toString().trim(),\n    country: (r.Country || '').toString().trim(),\n    sourceUrl: (r.sourceURL || '').toString().trim(),\n    nicheTargetId: (r.nicheTargetId != null ? r.nicheTargetId : (meta.nicheTargetId != null ? meta.nicheTargetId : null)),\n    emailVerified: emailVerified\n  });\n}\nconst segmentsPlanned = (meta && meta.segmentsPlanned != null) ? meta.segmentsPlanned : ((($('Build Groups').first() || {}).json || {}).expectedSegments || 0);\nconsole.log('[Prospect Payload] campaignId=' + campaignId + ' prospects=' + prospects.length + ' verified=' + prospects.filter(p => p.emailVerified).length + ' segmentsPlanned=' + segmentsPlanned);\nreturn [{ json: { campaignId: campaignId, segmentsPlanned: segmentsPlanned, prospects: prospects } }];"} },
  output: [{"campaignId": "c1", "segmentsPlanned": 4, "prospects": [{"email": "info@acme.de", "companyName": "Acme GmbH", "website": "https://acme.de", "city": "Berlin", "country": "Germany", "sourceUrl": "https://acme.de", "nicheTargetId": 10, "emailVerified": true}]}]
});

